const items = $input.all();

if (!items || items.length === 0) {
  throw new Error('No input data received');
}

const firstItem = items[0];
const body = firstItem.json?.body || firstItem.json;

if (!body || !body.job_post || !body.resume) {
  throw new Error('Missing job_post or resume data. Please check webhook input.');
}

const jobPostBuffer = Buffer.from(body.job_post.base64, 'base64');
const resumeBuffer = Buffer.from(body.resume.base64, 'base64');

return [
  {
    json: {
      user_email: body.user_email || 'unknown',
      user_id: body.user_id || 'unknown'
    },
    binary: {
      job_post: {
        data: jobPostBuffer.toString('base64'),
        mimeType: body.job_post.mime || 'text/plain',
        fileName: body.job_post.filename || 'job_post.txt'
      },
      resume: {
        data: resumeBuffer.toString('base64'),
        mimeType: body.resume.mime || 'text/plain',
        fileName: body.resume.filename || 'resume.txt'
      }
    }
  }
];

const data = $input.first().json;

const userEmail = $('WEBHOOK TRIGGER').first().json.body.user_email;

const coverLetterBase64 = $('AGREGATE-2').first().json['COVER LETTER'][0];

const resumeSummaryBase64 = $('AGREGATE-2').first().json['RESUME SUMMERY'][0];

function createBinaryData(base64String, fileName, mimeType = 'application/pdf') {
    if (!base64String) {
        throw new Error(`Base64 data missing for ${fileName}`);
    }
    const buffer = Buffer.from(base64String, 'base64');
    return {
        data: buffer.toString('base64'),
        mimeType: mimeType,
        fileName: fileName
    };
}

return [
    {
        json: {
            user_email: userEmail  
        },
        binary: {
            cover_letter_pdf: createBinaryData(coverLetterBase64, 'Cover_Letter.pdf'),
            resume_summary_pdf: createBinaryData(resumeSummaryBase64, 'Resume_Summary.pdf')
        }
    }
];
